from airflow.decorators import task


@task.virtualenv(
    requirements=['requests==2.31.0', 'python-dateutil==2.8.2'],
    system_site_packages=False,
)
def fetch_weather_forecast() -> dict:
    """Fetch weather data using a specific requests version.

    This function runs in an isolated virtual environment
    with only the specified packages installed.
    """
    import requests  # installed fresh in the virtual env
    response = requests.get('https://api.weather.lt/forecast')
    return response.json()
